require_once __DIR__.'/functions.php';if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}verify_csrf();$member=require_member();$id=filter_input(INPUT_POST,'post_id',FILTER_VALIDATE_INT);$stmt=db()->prepare("SELECT imagen FROM posts WHERE id=? AND member_author_id=? AND post_type='community'");$stmt->execute([$id,$member['id']]);$post=$stmt->fetch();if(!$post){http_response_code(403);exit('No puedes eliminar esta publicación.');}db()->prepare('DELETE FROM posts WHERE id=?')->execute([$id]);delete_image($post['imagen']);flash('Publicación eliminada.');redirect('/member-posts.php');
